create table dirkspzm32.edi_vda4987_pack_number (
    document_id        varchar2(32 char) not null enable,
    pack_item_id       varchar2(32 char) not null enable,
    pos                number(4, 0) not null enable,
    package_number1    varchar2(9 char),
    object_identifier1 varchar2(22 char),
    package_number2    varchar2(9 char),
    object_identifier2 varchar2(22 char),
    package_number3    varchar2(9 char),
    object_identifier3 varchar2(22 char),
    package_number4    varchar2(9 char),
    object_identifier4 varchar2(22 char),
    package_number5    varchar2(9 char),
    object_identifier5 varchar2(22 char),
    cod_no             number(1, 0)
);

alter table dirkspzm32.edi_vda4987_pack_number
    add constraint pk_edi_vda4987_pack_number primary key ( pack_item_id,
                                                            pos )
        using index enable;


